var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"제법 재미있는 술래잡기였어.","JPN":"なかなか楽しい鬼ごっこだったわ。","ENG":"That was a fun game of tag.","TWN":"真是場有趣的鬼抓人呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"......자기야.","JPN":"……ねえ、ダーリン。","ENG":"...Darling.","TWN":"親愛的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......넌?!","JPN":"……え！？","ENG":"...You?!","TWN":"你？！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"어떻게 이렇게 빨리?","JPN":"なぜこんな早く！？","ENG":"How did it catch up to us so quickly?","TWN":"怎麼可能這麼快？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"분명 마지막으로 확인된 위치는 한참이나 뒤에 있었는데.......","JPN":"最後に確認した位置は、ずっと後ろのほうだったのに……","ENG":"The last time I checked, it was way behind us...","TWN":"我最後一次確認時，你明明和我們有些距離啊……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"자기야, 자기야. 무지한 자기야.","JPN":"ねえ、ねえ、おバカなダーリン。","ENG":"Darling! Oh, you're so clueless.","TWN":"親愛的，親愛的，我無知的愛人啊。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"아직 잘 모르는구나?","JPN":"まだわからないのね。","ENG":"You don't get it, do you?","TWN":"妳還不知道嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"이곳은 나의 왕국이야.","JPN":"ここは私の王国。","ENG":"This is my kingdom.","TWN":"這裡可是我的王國呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"이 버려진 세계에서 공간적인 거리는 내게 아무런 의미도 없어.","JPN":"この見捨てられた世界で空間の距離なんて、なんの意味もないの。","ENG":"The concept of space and distance doesn't apply to me in this abandoned world.","TWN":"在這個被遺棄的世界裡，空間距離對我來說毫無意義。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"설마...... 그 정도의 장거리 공간 이동이 가능하다고?","JPN":"まさか……あんな長距離の空間移動までできちゃうわけ？","ENG":"You mean... You can teleport over that distance?","TWN":"你該不會……可以進行長距離的空間移動？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"아하하, 다른 자기들도 자기처럼 놀라더라.","JPN":"フフフ、他のダーリンたちもダーリンみたいに驚いてたわね。","ENG":"Hahaha! All the other darlings were shocked too!","TWN":"啊哈哈，其他的甜心們也和妳一樣驚訝呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그 말은......","JPN":"それはつまり……","ENG":"Does that mean...","TWN":"你這是……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"우릴 가지고 놀았다는 거냐!!","JPN":"俺たちを弄んでいたのか！！","ENG":"You've been toying with us?!","TWN":"在玩弄我們嗎！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"하하하, 자기야, 당연하잖아?","JPN":"アハハハ、ねえ、当然じゃない？","ENG":"Hahaha! Of course, my dear!","TWN":"哈哈哈，親愛的，這不是當然的嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"난 사냥감이 지칠 때까지 도망치는 모습을 보는 걸 세상에서 제일 좋아하거든.","JPN":"私はね、獲物が力尽きるまで逃げまわる姿を見るのが一番好きなの。","ENG":"There's nothing I enjoy more than to watch my prey run until they're exhausted.","TWN":"我最喜歡看獵物不停逃跑，直到筋疲力盡的樣子了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"땀 흘리고 지치고......","JPN":"汗まみれになって……ぐったりして……","ENG":"To watch them sweat and run out of breath...","TWN":"滿頭大汗、疲憊不已……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"절망에 가득한 표정을 짓는 모습을 말이지.","JPN":"絶望に満ちた顔をするのがたまらないの。","ENG":"and see their faces fill with despair.","TWN":"表情充滿了絕望。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};